    }

    location @healthz_fallback {
        return 200 '{"ok":true,"gateway":"starting"}';
        default_type application/json;
    }

    ${HOOKS_LOCATION_BLOCK}

    location / {
        ${AUTH_BLOCK}

        ${OCW_PROXY_PASS}
        ${OCW_AUTH_HDR}

        proxy_set_header Host \$host;
        proxy_set_header X-Real-IP \$remote_addr;
        proxy_set_header X-Forwarded-For \$proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto \$scheme;

        proxy_http_version 1.1;
        proxy_set_header Upgrade \$http_upgrade;
        proxy_set_header Connection \$connection_upgrade;

        proxy_read_timeout 86400s;
        proxy_send_timeout 86400s;

        proxy_set_header Accept-Encoding "";
        sub_filter_once on;
        sub_filter '</body>' '<div id="oc-version-badge" style="position:fixed;bottom:8px;right:8px;z-index:99999;background:rgba(0,0,0,0.65);color:#9fdfbf;font-family:monospace;font-size:11px;padding:3px 8px;border-radius:4px;pointer-events:none;letter-spacing:0.03em;">${VERSION_BADGE_TEXT}</div></body>';

        error_page 502 503 504 /starting.html;
    }

    location = /starting.html {
        root /usr/share/nginx/html;
        internal;
    }

    location = /step.txt {
        root /usr/share/nginx/html;
        default_type text/plain;
        add_header Cache-Control no-store;
    }

    # Gateway crash log — auth-protected diagnostic endpoint
    location = /gateway.log {
        ${AUTH_BLOCK}
        alias ${STATE_DIR}/gateway.log;
        default_type text/plain;
        add_header Cache-Control no-store;
    }

    # Browser sidecar proxy (VNC web UI)
    location /browser/ {
        ${AUTH_BLOCK}

        resolver 127.0.0.11 valid=10s ipv6=off;
        set \$browser_upstream "http://browser:3000";
        rewrite ^/browser/(.*) /\$1 break;
        proxy_pass \$browser_upstream;
        proxy_set_header Host \$host;
        proxy_set_header X-Real-IP \$remote_addr;
        proxy_set_header X-Forwarded-For \$proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto \$scheme;

        proxy_http_version 1.1;
        proxy_set_header Upgrade \$http_upgrade;
        proxy_set_header Connection \$connection_upgrade;

        proxy_read_timeout 86400s;
